interface PricingSectionSingleProps {
  plans?: PricingPlan[];
  plan?: PricingPlan;
  children?: React.ReactNode;
}

export function PricingSectionSingle({ plans, plan, children }: PricingSectionSingleProps) {
  // Use the provided single plan, or the first plan from the plans array
  const selectedPlan = plan || (plans?.length ? plans[0] : null);

  if (!selectedPlan) {
    return null;
  }

  const price =
    selectedPlan.price.monthly || selectedPlan.price.annually || selectedPlan.price.oneTime || 0;

  return (
    <div className="relative w-full text-white">
      {/* Background gradient effect */}
      <div className="container mx-auto p-4">
        <Card className="relative mx-auto max-w-3xl overflow-hidden border-purple-500/50 backdrop-blur-sm transition-shadow duration-300 hover:shadow-xl hover:shadow-purple-500/10">
          <div className="absolute inset-0 bg-gradient-to-br from-purple-500/10 via-transparent to-transparent" />
          <div className="absolute -right-32 -top-32 h-64 w-64 rounded-full bg-purple-500/10 blur-[100px]" />

          <CardHeader className="relative space-y-4 p-8 text-center sm:p-12">
            <div className="flex items-center justify-center gap-2">
              <h2 className="text-3xl font-bold sm:text-4xl">{selectedPlan.title}</h2>
              {selectedPlan.isBestValue && <Sparkles className="h-6 w-6 text-purple-400" />}
            </div>

            <div className="space-y-2">
              <div className="flex items-center justify-center gap-3">
                <span className="text-5xl font-bold sm:text-6xl">${price}</span>
              </div>
              {selectedPlan.description && (
                <div className="border-gray-800 pt-8 text-center text-sm text-gray-400">
                  <p>{selectedPlan.description}</p>
                </div>
              )}
            </div>
          </CardHeader>
          <CardContent className="relative space-y-8 p-8 sm:p-12">
            <Separator />

            <div className="grid gap-6 sm:grid-cols-2">
              {selectedPlan.features.map((feature) => (
                <div key={feature} className="flex items-center gap-2">
                  <Check className="h-5 w-5 shrink-0 text-purple-400" />
                  <span className="text-base">{feature}</span>
                </div>
              ))}
            </div>

            <div className="pt-4">
              {selectedPlan.isComingSoon ? (
                <Button
                  disabled
                  className={cn("w-full bg-purple-500 text-lg text-white hover:bg-purple-600")}
                >
                  Coming Soon
                </Button>
              ) : (
                <Link
                  href={selectedPlan.href}
                  className={cn(
                    buttonVariants({ variant: "default" }),
                    "w-full bg-purple-500 text-lg text-white transition-all duration-200 hover:bg-purple-600 hover:scale-[1.02] active:scale-[0.98]"
                  )}
                >
                  Get {selectedPlan.title} Now
                </Link>
              )}
            </div>
          </CardContent>
          {children && (
            <CardFooter className="relative flex flex-col gap-4">
              <Separator />
              {children}
            </CardFooter>
          )}
        </Card>
      </div>
    </div>
  );
}

import type { Config } from "@/payload-types";
import { getPayloadCollection } from "./get-payload-collection";

type Collections = Config["collections"];
type CollectionKey = keyof Collections;

interface PayloadRichText {
  [key: string]: unknown;
  root: {
    type: string;
    children: {
      [key: string]: unknown;
      type: string;
      version: number;
      children?: { text: string }[];
    }[];
    direction: "ltr" | "rtl" | null;
    format: "" | "left" | "start" | "center" | "right" | "end" | "justify";
    indent: number;
    version: number;
  };
}

/**
 * Check if a value is a Payload rich text field
 */
const isRichTextField = (value: unknown): value is PayloadRichText => {
  if (!value || typeof value !== "object") return false;
  const obj = value as Record<string, unknown>;
  return (
    "root" in obj &&
    typeof obj.root === "object" &&
    obj.root !== null &&
    "children" in obj.root &&
    Array.isArray(obj.root.children)
  );
};

/**
 * Extract text content from a rich text field
 */
const extractRichText = (richText: PayloadRichText): string => {
  try {
    return (
      richText?.root?.children
        .map((child) => {
          const textNode = child?.children?.[0];
          return textNode?.text || "";
        })
        .join("\n") || ""
    );
  } catch (error) {
    console.error("Error extracting rich text:", error);
    return "";
  }
};

/**
 * Recursively process an object to convert rich text fields to plain text
 */
const processContent = <T>(content: T): T => {
  if (Array.isArray(content)) {
    return content.map((item) => processContent(item)) as T;
  }

  if (content && typeof content === "object") {
    const processed: Record<string, unknown> = {};

    for (const [key, value] of Object.entries(content)) {
      if (isRichTextField(value)) {
        processed[key] = extractRichText(value);
      } else if (typeof value === "object" && value !== null) {
        const processedValue = processContent(value);
        processed[key] = isRichTextField(processedValue)
          ? extractRichText(processedValue)
          : processedValue;
      } else {
        processed[key] = value;
      }
    }

    return processed as T;
  }

  return content;
};

/**
 * Helper function to fetch content from Payload CMS with fallback to static content
 * Automatically converts rich text fields to plain text
 * @param collection - The collection to fetch from
 * @param options - Options for the collection query
 * @param fallbackImport - Function that imports the static content
 * @returns The content from Payload or the static fallback, with rich text converted to plain text
 */
export async function getPayloadContent<T extends CollectionKey, F>({
  collection,
  options = {},
  fallbackImport,
}: {
  collection: T;
  options?: Parameters<typeof getPayloadCollection>[1];
  fallbackImport: () => Promise<{ content: F }>;
}): Promise<Collections[T][] | F> {
  try {
    // Attempt to fetch from Payload
    const payloadContent = await getPayloadCollection(collection, options).catch(async (error) => {
      console.warn(
        `Error fetching ${collection} from payload, falling back to static content: `,
        error
      );
      return null;
    });

    // If Payload fetch successful, process and return the content
    if (payloadContent && payloadContent.length > 0) {
      return processContent(payloadContent);
    }

    // Otherwise, try to load static content
    const { content } = await fallbackImport();
    return processContent(content);
  } catch (error) {
    console.error(`Error fetching content for ${collection}:`, error);
    throw error; // Let the component handle the error
  }
}
